@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";

/* Theme files, each defines brand primitives + semantic tokens for one theme */
@import "../themes/ag-core.css";
@import "../themes/navy.css";
@import "../themes/ns-pro.css";

@custom-variant dark (&:is(.dark *):not(:is(.light *)));

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-sans);
  --font-mono: var(--font-mono);
  --font-heading: var(--font-display);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-brand: var(--brand);
  --color-chart-7: var(--chart-7);
  --color-chart-6: var(--chart-6);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  /* NS Pro badge tokens, only defined under [data-theme="ns-pro"]. */
  /* Undefined (transparent) in all other themes. See NS Pro rules in CLAUDE.md. */
  --color-ns-badge-1: var(--ns-badge-1);
  --color-ns-badge-2: var(--ns-badge-2);
  --color-ns-badge-3: var(--ns-badge-3);
  --color-ns-badge-4: var(--ns-badge-4);
  --color-ns-badge-5: var(--ns-badge-5);
  --color-ns-badge-6: var(--ns-badge-6);
  --color-ns-badge-7: var(--ns-badge-7);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) * 1.4);
  --radius-2xl: calc(var(--radius) * 1.8);
  --radius-3xl: calc(var(--radius) * 2.2);
  --radius-4xl: calc(var(--radius) * 2.6);

  /* ==========================================================================
     TYPE SCALE PRIMITIVES
     Declaring these here registers them as owned tokens, change any value and
     every text-* utility that references it updates automatically.
     Tailwind's defaults are preserved below; adjust as the system evolves.
     ========================================================================== */
  --text-xs:   0.75rem;   /* 12px */
  --text-sm:   0.875rem;  /* 14px */
  --text-base: 1rem;      /* 16px */
  --text-lg:   1.125rem;  /* 18px */
  --text-xl:   1.25rem;   /* 20px */
  --text-2xl:  1.5rem;    /* 24px */
  --text-3xl:  1.875rem;  /* 30px */
  --text-4xl:  2.25rem;   /* 36px */
  --text-5xl:  3rem;      /* 48px */
  --text-6xl:  3.75rem;   /* 60px */
  --text-7xl:  4.5rem;    /* 72px */
  --text-8xl:  6rem;      /* 96px */
  --text-9xl:  8rem;      /* 128px */
}

/* =============================================================================
   SHARED PRIMITIVE TOKENS
   Neutral palette, shared across all themes. Brand and chart primitives live
   in each theme's own CSS file (src/themes/[id].css).
   Naming: --primitive-[palette]-[lightness-step]
   ============================================================================= */

:root {
  /* Neutral, warm grays and browns */
  --primitive-neutral-15:  #0C0A09;  /* deepest dark brown */
  --primitive-neutral-21:  #1D1816;  /* dark warm brown */
  --primitive-neutral-27:  #2B2422;  /* dark warm muted */
  --primitive-neutral-43:  #544F4D;  /* muted foreground anchor */
  --primitive-neutral-55:  #7C6D67;  /* muted mid brown */
  --primitive-neutral-71:  #ABA09C;  /* medium warm gray */
  --primitive-neutral-92:  #E5E3DF;  /* warm-tinted border */
  --primitive-neutral-92w: #E8E4E3;  /* near-white warm (dark mode CTA) */
  --primitive-neutral-96:  #F4F2EF;  /* warm cream tint */
  --primitive-neutral-98:  #F8F7F4;  /* warm cream background */
  --primitive-neutral-99:  #FBFAF9;  /* near-white */
  --primitive-neutral-100: #FFFEFD;  /* near-white cream */
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
  html {
    font-family: var(--font-sans);
    color-scheme: light;
    scrollbar-width: thin;
    scrollbar-color: color-mix(in oklab, var(--muted-foreground) 45%, transparent)
      transparent;
  }

  html.dark {
    color-scheme: dark;
  }

  html.light {
    color-scheme: light;
  }

  /* Themed scrollbars on overflow containers (respects light/dark tokens). */
  :where(
    .overflow-auto,
    .overflow-y-auto,
    .overflow-x-auto,
    .overflow-scroll
  ):not(.scrollbar-hidden) {
    scrollbar-width: thin;
    scrollbar-color: color-mix(in oklab, var(--muted-foreground) 45%, transparent)
      transparent;
  }

  :where(
    .overflow-auto,
    .overflow-y-auto,
    .overflow-x-auto,
    .overflow-scroll
  ):not(.scrollbar-hidden)::-webkit-scrollbar {
    width: 10px;
    height: 10px;
  }

  :where(
    .overflow-auto,
    .overflow-y-auto,
    .overflow-x-auto,
    .overflow-scroll
  ):not(.scrollbar-hidden)::-webkit-scrollbar-track {
    background: transparent;
  }

  :where(
    .overflow-auto,
    .overflow-y-auto,
    .overflow-x-auto,
    .overflow-scroll
  ):not(.scrollbar-hidden)::-webkit-scrollbar-thumb {
    background-color: color-mix(in oklab, var(--muted-foreground) 40%, transparent);
    border: 2px solid transparent;
    background-clip: content-box;
    border-radius: 9999px;
  }

  :where(
    .overflow-auto,
    .overflow-y-auto,
    .overflow-x-auto,
    .overflow-scroll
  ):not(.scrollbar-hidden)::-webkit-scrollbar-thumb:hover {
    background-color: color-mix(in oklab, var(--muted-foreground) 60%, transparent);
  }
  /* Default heading sizes, Tailwind preflight resets all headings to body size,
     so we re-establish the scale here. Explicit size classes on individual
     elements will still override these.

     Bitter (--font-display) is the heading typeface for h1 through h6.
     Load Bitter at weight 400 only; do not apply font-semibold or font-bold
     to headings. */
  h1 {
    font-family: var(--font-display);
    @apply !text-4xl tracking-tight;
  }
  h2 {
    font-family: var(--font-display);
    @apply !text-3xl tracking-tight;
  }
  h3 {
    font-family: var(--font-display);
    @apply !text-2xl tracking-tight;
  }
  h4 {
    font-family: var(--font-display);
    @apply !text-xl;
  }
  h5 {
    font-family: var(--font-display);
    @apply !text-lg;
  }
  h6 {
    font-family: var(--font-display);
    @apply !text-base;
  }
}

/* =============================================================================
   DISPLAY UTILITIES
   Large editorial text sizes using Bitter (--font-display).
   These are registered as Tailwind utilities so modifiers (responsive, etc.)
   work correctly.
   ============================================================================= */

@utility text-display-78 {
  font-family: var(--font-display);
  font-size: 78px;
  line-height: 1.05;
  letter-spacing: -0.02em;
}

@utility text-display-60 {
  font-family: var(--font-display);
  font-size: 60px;
  line-height: 1.08;
  letter-spacing: -0.02em;
}

/* Themed scrollbars that follow light/dark semantic tokens. */
@utility scrollbar-themed {
  scrollbar-width: thin;
  scrollbar-color: color-mix(in oklab, var(--muted-foreground) 45%, transparent)
    transparent;

  &::-webkit-scrollbar {
    width: 10px;
    height: 10px;
  }

  &::-webkit-scrollbar-track {
    background: transparent;
  }

  &::-webkit-scrollbar-thumb {
    background-color: color-mix(in oklab, var(--muted-foreground) 40%, transparent);
    border: 2px solid transparent;
    background-clip: content-box;
    border-radius: 9999px;
  }

  &::-webkit-scrollbar-thumb:hover {
    background-color: color-mix(in oklab, var(--muted-foreground) 60%, transparent);
  }
}

/* Hide scrollbars while keeping scroll (mouse wheel, trackpad, keyboard). */
@utility scrollbar-hidden {
  scrollbar-width: none;
  -ms-overflow-style: none;

  &::-webkit-scrollbar {
    display: none;
  }
}

/* =============================================================================
   NS CORE THEME, src/themes/ag-core.css
   Project North Star core brand theme.
   Selector: [data-theme="ag"]
   Applied by ThemeProvider via document.documentElement.dataset.theme = "ag"
   ============================================================================= */

/* --- Brand & chart primitives specific to NS -------------------------------- */

[data-theme="ag"] {
  /* Brand, Sapphire accent */
  --primitive-brand-58: #72B0AB;  /* Sapphire, base brand */
  --primitive-brand-63: #9CC9C5;  /* lightened Sapphire for dark mode */

  /* Chart scale, light mode (dark → light) */
  --primitive-chart-43:  #544F4D;  /* darkest */
  --primitive-chart-50:  #676361;  /* step 2 */
  --primitive-chart-57:  #7B7776;  /* step 3 */
  --primitive-chart-65:  #938F8D;  /* step 4 */
  --primitive-chart-73:  #ABA7A6;  /* lightest */

  /* Chart scale, dark mode (dark → light) */
  --primitive-chart-15:  #0D0B0A;  /* darkest */
  --primitive-chart-22:  #1D1A19;  /* step 2 */
  --primitive-chart-29:  #2E2B2A;  /* step 3 */
  --primitive-chart-36:  #403D3C;  /* step 4 */
  --primitive-chart-43d: #544F4D;  /* lightest */
}

/* --- Light mode semantic tokens --------------------------------------------- */

[data-theme="ag"],
[data-theme="ag"].light {
  --background:             var(--primitive-neutral-98);   /* #F9F8F5 warm cream */
  --foreground:             var(--primitive-neutral-15);
  --card:                   var(--primitive-neutral-100);  /* #FEFDFC near-white cream */
  --card-foreground:        var(--primitive-neutral-15);
  --popover:                var(--primitive-neutral-100);
  --popover-foreground:     var(--primitive-neutral-15);
  --brand:                  var(--primitive-brand-58);     /* #72B0AB Sapphire */
  --primary:                var(--primitive-neutral-21);
  --primary-foreground:     var(--primitive-neutral-99);
  --secondary:              var(--primitive-neutral-96);
  --secondary-foreground:   var(--primitive-neutral-21);
  --muted:                  var(--primitive-neutral-96);
  --muted-foreground:       var(--primitive-neutral-43);  /* #544F4D */
  --accent:                 var(--primitive-neutral-96);
  --accent-foreground:      var(--primitive-neutral-21);
  --destructive:            #DC2626;
  --border:                 var(--primitive-neutral-92);
  --input:                  var(--primitive-neutral-92);
  --ring:                   var(--primitive-brand-58);
  --chart-1:                var(--primitive-chart-43);
  --chart-2:                var(--primitive-chart-50);
  --chart-3:                var(--primitive-chart-57);
  --chart-4:                var(--primitive-chart-65);
  --chart-5:                var(--primitive-chart-73);
  --radius:                 4px;
  --sidebar:                var(--primitive-neutral-100);
  --sidebar-foreground:     var(--primitive-neutral-15);
  --sidebar-primary:        var(--primitive-neutral-21);
  --sidebar-primary-foreground: var(--primitive-neutral-99);
  --sidebar-accent:         var(--primitive-neutral-96);
  --sidebar-accent-foreground:  var(--primitive-neutral-21);
  --sidebar-border:         var(--primitive-neutral-92);
  --sidebar-ring:           var(--primitive-brand-58);
}

/* --- Dark mode semantic tokens ---------------------------------------------- */

[data-theme="ag"].dark {
  --background:             var(--primitive-neutral-15);
  --foreground:             var(--primitive-neutral-99);
  --card:                   var(--primitive-neutral-21);
  --card-foreground:        var(--primitive-neutral-99);
  --popover:                var(--primitive-neutral-21);
  --popover-foreground:     var(--primitive-neutral-99);
  --brand:                  var(--primitive-brand-63);
  --primary:                var(--primitive-neutral-92w);
  --primary-foreground:     var(--primitive-neutral-21);
  --secondary:              var(--primitive-neutral-27);
  --secondary-foreground:   var(--primitive-neutral-99);
  --muted:                  var(--primitive-neutral-27);
  --muted-foreground:       var(--primitive-neutral-71);
  --accent:                 var(--primitive-neutral-27);
  --accent-foreground:      var(--primitive-neutral-99);
  --destructive:            #F87171;
  --border:                 rgba(255, 255, 255, 0.10);
  --input:                  rgba(255, 255, 255, 0.15);
  --ring:                   var(--primitive-brand-63);
  /* Reversed light-mode scale, lighter values contrast on the dark surface */
  --chart-1:                var(--primitive-chart-73);   /* #ABA7A6 lightest */
  --chart-2:                var(--primitive-chart-65);   /* #938F8D */
  --chart-3:                var(--primitive-chart-57);   /* #7B7776 */
  --chart-4:                var(--primitive-chart-50);   /* #676361 */
  --chart-5:                var(--primitive-chart-43);   /* #544F4D darkest */
  --sidebar:                var(--primitive-neutral-21);
  --sidebar-foreground:     var(--primitive-neutral-99);
  --sidebar-primary:        var(--primitive-neutral-92w);
  --sidebar-primary-foreground: var(--primitive-neutral-21);
  --sidebar-accent:         var(--primitive-neutral-27);
  --sidebar-accent-foreground:  var(--primitive-neutral-99);
  --sidebar-border:         rgba(255, 255, 255, 0.10);
  --sidebar-ring:           var(--primitive-brand-63);
}
